query GetContainersMetrics(
  $accountTag: string!
  $datetimeStart: Time
  $datetimeEnd: Time
  $applicationId: string
) {
  viewer {
    accounts(filter: { accountTag: $accountTag }) {
      containersMetricsAdaptiveGroups(
        limit: 10000
        filter: {
          applicationId: $applicationId
          datetimeMinute_geq: $datetimeStart
          datetimeMinute_leq: $datetimeEnd
          procType: "user"
          active: 1
        }
      ) {
        avg {
          cpuUtilization
        }
        quantiles {
          cpuUtilizationP50
          cpuUtilizationP90
          cpuUtilizationP99
        }
        dimensions {


        }
      }
    }
  }
}

